"use client";

import { type FrostGlassVariantProp, glassVariantStyles } from "@/lib/glass-variants";
import { cn } from "@/lib/utils";

import { ButtonGroup, ButtonGroupSeparator, ButtonGroupText } from "../button-group";
import { GlassSeparator } from "./glass-separator";
import { LiquidGlass } from "./liquid-glass";

type GlassButtonGroupProps = React.ComponentProps<typeof ButtonGroup> & FrostGlassVariantProp;

function GlassButtonGroup({ className, glassVariant = "clear", children, ...props }: GlassButtonGroupProps) {
  if (glassVariant === "liquid-refract") {
    return (
      <LiquidGlass className={cn("", className)}>
        <ButtonGroup
          data-slot="glass-button-group"
          data-glass-variant={glassVariant}
          className={cn("bg-transparent", className)}
          {...props}
        >
          {children}
        </ButtonGroup>
      </LiquidGlass>
    );
  }

  return (
    <ButtonGroup
      data-slot="glass-button-group"
      data-glass-variant={glassVariant}
      className={cn("rounded-lg", glassVariantStyles[glassVariant], className)}
      {...props}
    >
      {children}
    </ButtonGroup>
  );
}

type GlassButtonGroupTextProps = React.ComponentProps<typeof ButtonGroupText> & FrostGlassVariantProp;

function GlassButtonGroupText({ className, glassVariant = "clear", ...props }: GlassButtonGroupTextProps) {
  return (
    <ButtonGroupText
      data-slot="glass-button-group-text"
      data-glass-variant={glassVariant}
      className={cn(
        "border-0 bg-transparent",
        glassVariant !== "liquid-refract" && "text-foreground",
        className
      )}
      {...props}
    />
  );
}

type GlassButtonGroupSeparatorProps = React.ComponentProps<typeof ButtonGroupSeparator> & FrostGlassVariantProp;

function GlassButtonGroupSeparator({ className, glassVariant = "clear", ...props }: GlassButtonGroupSeparatorProps) {
  return (
    <GlassSeparator
      data-slot="glass-button-group-separator"
      glassVariant={glassVariant}
      className={cn(
        "relative self-stretch data-horizontal:mx-px data-horizontal:w-auto data-vertical:my-px data-vertical:h-auto",
        className
      )}
      {...props}
    />
  );
}

export { GlassButtonGroup, GlassButtonGroupSeparator, GlassButtonGroupText };
